def update_config(self, save_directory: str) -> None:
    """
    Update the model config located at save_directory with compression configs

    :param save_directory: path to a folder containing a HF model config
    """
    if not any((self.quantization_config, self.transform_config)):
        return

    config_file_path = os.path.join(save_directory, CONFIG_NAME)
    if os.path.exists(config_file_path):
        with open(config_file_path, "r") as file:
            config_data = json.load(file)
    else:
        config_data = {}

    qconfig_data = (
        self.quantization_config.model_dump(exclude=["quant_method"])
        if self.quantization_config is not None
        else {}
    )
    tconfig_data = (
        self.transform_config.model_dump()
        if self.transform_config is not None
        else {}
    )

    config_data[QUANTIZATION_CONFIG_NAME] = {
        COMPRESSION_VERSION_NAME: compressed_tensors.__version__,
        QUANTIZATION_METHOD_NAME: QUANTIZATION_METHOD,
        SPARSITY_CONFIG_NAME: {},  # sparsity is removed for now
        TRANSFORM_CONFIG_NAME: tconfig_data,
        **qconfig_data,
    }

    with open(config_file_path, "w") as config_file:
        json.dump(config_data, config_file, indent=2, sort_keys=True)

def match_named_modules(
    model: torch.nn.Module,
    targets: Iterable[str] | None,
    ignore: Iterable[str] | None = None,
    fused: FusedMappping | None = None,
    warn_on_fail: bool = False,
) -> Generator[tuple[str, torch.nn.Module], None, None]:
    """
    Yields names and modules which match `targets` but do not match `ignore`.
    Values are returned in order of `model.named_modules()`

    :param model: model containing submodules to match against
    :param targets: target strings, potentially containing "re:" prefixes
    :param ignore: targets to ignore, potentially containing "re:" prefixes
    :fused: optional mapping from suffixes of fused modules to the suffixes of their
        corresponding shards. See `compressed_tensors.utils.match.is_match`
    :param warn_on_fail: if True, warns if any targets do not match any modules in model
    :return: generator of module names and modules
    """
    targets = targets or []
    ignore = ignore or []

    unmatched_targets = set(targets)

    for name, module in model.named_modules():
        for target in targets:
            if is_match(name, module, target, fused=fused):
                unmatched_targets -= {target}
                if not is_match(name, module, ignore, fused=fused):
                    yield name, module
                break

    if warn_on_fail:
        for target in unmatched_targets:
            _LOGGER.warning(
                f"Could not match `{target}` in instance of {model.__class__.__name__}"
            )

